function parseNpsScore(message) {
  if (!message || typeof message !== 'string') return null;
  const matches = message.matchAll(/\b(\d{1,3})\b/g);
  for (const m of matches) {
    const n = Number(m[1]);
    if (Number.isInteger(n) && n >= 0 && n <= 10) return n;
  }
  return null;
}
const input = $('When Called').item.json;
const lookup = $('Lookup Pending NPS').item.json;
const score = parseNpsScore(input.mensagem);
return { json: {
  ...input,
  feedback_id: lookup.id,
  score
}};

